-- ============================================================
-- Этап 1 «Фундамент» (foundation) проекта Homesteader's Cabin —
-- эталонный контент из ЭТАП1_Фундамент.md («для бабушки», реальные
-- данные техпаспорта). Особый случай про торф/сваи — в hint шага
-- разметки; скрипт переговоров с бригадой — в hint шага заливки.
-- Идемпотентно: пересоздаёт только шаги этапа foundation (id ...311);
-- Этап 0 и остальные этапы не трогает. Без этапа 311 — тихо пропуск.
-- ============================================================

do $do$
begin
  if not exists (select 1 from stages
                 where id = 'de300000-0000-4000-8000-000000000311') then
    return;
  end if;

  update stages set intro = 'Дом не ставят прямо на землю — он стоит на «ножках»: крепких бетонных столбах, вкопанных в грунт. Их называют столбчатым фундаментом. Это как табуретка: несколько прочных ножек держат всё сверху.

Почему именно столбы, а не сплошная лента? Для лёгкого каркасного дома этого достаточно, это дешевле, проще и быстрее — тебе не нужен бетономешалка-завод и бригада. Справишься сам с помощником.

Займёт 3-5 дней (плюс бетон должен постоять, набрать прочность). Не спеши — от ровности опор зависит, будет ли дом стоять прямо. Это самый ответственный этап: тут закладывается «здоровье» всего дома. Но я всё покажу по шагам.

Важно: ты уже узнал в Этапе 0, какая у тебя земля (помнишь тест с колбаской?). Если земля оказалась торфяной или вода стоит высоко — в подсказке шага разметки я подскажу, что делать иначе.'
  where id = 'de300000-0000-4000-8000-000000000311';

  delete from steps where stage_id = 'de300000-0000-4000-8000-000000000311';

  insert into steps (id, stage_id, sort, title, why_text, prep_text, actions, tools,
    self_check, hint, common_mistake, helpers_needed) values
  ('de300000-0000-4000-8000-000000000421',
   'de300000-0000-4000-8000-000000000311', 1,
   'Размечаем, где будут стоять опоры',
   'Прежде чем копать, надо точно разметить на земле, где встанут столбы. Ошибёшься с разметкой — дом получится кривой. Меряем один раз спокойно, копаем потом.',
   'Помощник — тут очень пригодится (одному тянуть рулетку неудобно).',
   '["Дом у нас 3,66 м в ширину и 7,32 м в длину (запомни эти два числа). Отметь колышками 4 угла дома — вбей колышек в каждый угол.","Проверь, что получился ровный прямоугольник: измерь обе диагонали (от угла до угла крест-накрест). Диагональ — это линия из одного угла в противоположный. Обе цифры должны совпасть (разница не больше 1 см) — тогда углы прямые, дом не «косой».","Натяни шнурку между колышками по периметру — это контур дома.","Размечай места опор: столбы стоят рядами. По ширине — по краям (3,66 м между крайними). По длине дом 7,32 м, опоры ставим рядами примерно через 1,68 м — получается 5 рядов опор. Отметь колышком каждое место столба."]',
   '{"рулетка 10 м","колышки (10-15 шт)","шнурка (верёвка)","молоток"}',
   '["Отметил 4 угла, прямоугольник 3,66 × 7,32 м","Диагонали совпали (разница ≤1 см)","Размечены все места опор колышками (5 рядов)"]',
   'Правило египетского треугольника для прямого угла: отмерь по одной стороне 3 метра, по другой 4 метра, а между их концами должно быть ровно 5 метров. Если так — угол идеально прямой. Простая проверка без приборов.

Особый случай — если у тебя плохая земля. Помнишь тест грунта в Этапе 0? Если земля торфяная (тёмная, рыхлая, пружинит) — бетонные столбы просядут: тебе нужны винтовые сваи — металлические «саморезы» длиной 2,5-3 м, которые вкручивают до плотного слоя. Их можно вкрутить втроём вручную или заказать бригаду. Если вода стоит высоко после дождя — тоже смотри в сторону свай, они не боятся воды. Винтовые сваи дороже бетона, зато без копки и работают на слабых грунтах. Если сомневаешься — это тот случай, где стоит разово посоветоваться со специалистом по сваям (замер и расчёт часто бесплатны у продавцов свай).',
   'Копать сразу, «на глаз». Потом окажется, что столбы не в ряд, и балка не ляжет. Разметка — это медленно и скучно, но именно она спасает от кривого дома.',
   1),
  ('de300000-0000-4000-8000-000000000422',
   'de300000-0000-4000-8000-000000000311', 2,
   'Копаем ямы под опоры',
   'Столбы должны опираться на плотный грунт НИЖЕ глубины промерзания — иначе зимой землю «вспучит» морозом и дом поведёт. Это главное правило фундамента в холодном климате.',
   '',
   '["Узнай глубину промерзания в своём районе (в средней полосе России это примерно 1,5 метра, севернее — глубже; можно спросить у соседей-строителей или в интернете по своему городу).","В каждой размеченной точке выкопай яму глубже глубины промерзания — то есть примерно 1,5-1,7 м. Ширина ямы около 40 см.","Дно ямы утрамбуй, насыпь подушку из песка и щебня 15-20 см, снова утрамбуй. Подушка нужна, чтобы опора не проседала и вода уходила."]',
   '{"лопата штыковая","бур садовый (если есть)","рулетка","ведро","тачка"}',
   '["Все ямы выкопаны ниже глубины промерзания (~1,5 м)","На дне утрамбованная подушка песок+щебень","Ямы примерно одинаковой глубины"]',
   'Копать 1,5 м лопатой тяжело. Варианты полегче: взять напрокат мотобур, или пригласить помощника с ручным буром, или (для винтовых свай) вообще пропустить копку — смотри «особый случай» в подсказке шага разметки.',
   'Сделать ямы мелкими «чтобы полегче». Морозное пучение зимой поднимет мелкие опоры, и дом перекосит, пойдут трещины. Глубина — это не там, где надоело копать, а ниже промерзания. Обязательно.',
   0),
  ('de300000-0000-4000-8000-000000000423',
   'de300000-0000-4000-8000-000000000311', 3,
   'Заливаем бетонные столбы',
   'Теперь в ямы ставим опалубку (форму) и заливаем бетон — получаются прочные столбы, на которых встанет дом.',
   'Купи заранее (из сметы): труба-опалубка (картонная или пластиковая) или рубероид, свёрнутый трубой — по числу опор; цемент, песок, щебень (или готовая бетонная смесь), вода; арматура (прутья) для усиления; анкерные болты или закладные пластины (чтобы потом прикрепить балку).',
   '["Опусти в яму трубу-опалубку так, чтобы она выступала над землёй на 20-30 см (чтобы дерево дома не касалось земли и не гнило).","Вставь внутрь 2-3 прута арматуры для прочности.","Замешай бетон (или привези готовый) и залей трубу. Протыкай прутом, чтобы вышел воздух.","Уровнем проверь, что верх всех столбов на одной высоте — это критично, иначе дом будет стоять криво. Выравнивай, пока бетон не схватился.","В верх каждого столба вставь анкерный болт/закладную (к ней прикрутишь балку).","Дай бетону постоять минимум 3-7 дней (лучше больше), он должен набрать прочность. Не спеши строить сверху сразу."]',
   '{"бетономешалка (аренда) или корыто для замеса","уровень"}',
   '["Все столбы залиты, выступают над землёй 20-30 см","Верх всех столбов на одном уровне (проверено уровнем)","В столбы вставлены анкеры/закладные для балки","Бетон стоит и набирает прочность (не нагружаю)"]',
   'Проще всего заказать готовый бетон миксером, если есть подъезд — не будешь замешивать вручную десятки замесов. Дороже, но экономит спину и день работы.

СКРИПТ — разговор с бригадой по фундаменту (если решишь не сам). Спрашивай: «На какую глубину ставите столбы/сваи?» — должно быть НИЖЕ промерзания (для средней полосы 1,5-1,8 м), если говорят «на метр хватит» — это халтура, зимой поведёт; «Даёте гарантию? Пишете в договоре?»; «Делаете гидроизоляцию между бетоном и деревом?»; «Проверяете уровень верха опор?». Хорошие ответы: «Глубже промерзания, есть акт с замерами», «Гарантия 2-3 года в договоре». Красные флаги (беги): «Метра хватит, все так делают» — не хватит, будет пучение; «Работаем без договора» — спросить будет не с кого; цена вдвое ниже рынка — сэкономят на глубине или бетоне. Ориентир: фундамент обычно 10-15% от стоимости дома. Для нашего дома столбчатый — самый бюджетный вариант.',
   'Нагружать столбы, пока бетон свежий. Он крепнет неделями. Поспешишь — треснет.',
   0),
  ('de300000-0000-4000-8000-000000000424',
   'de300000-0000-4000-8000-000000000311', 4,
   'Кладём опорные балки (обвязку по опорам)',
   'На бетонные столбы ложатся толстые деревянные балки — на них потом встанет весь каркас пола. Это «мостик» между бетонными ножками и деревянным домом.',
   'Купи заранее: балки 100×200 мм (в оригинале 4×8 дюймов) — по длине дома, вдоль рядов опор; гидроизоляция (рубероид) — проложить между бетоном и деревом; анкерные гайки/крепёж; антисептик для дерева (нижние балки особенно гниют).',
   '["На каждый столб положи кусок гидроизоляции (рубероид) — дерево не должно касаться бетона напрямую, иначе тянет влагу и гниёт.","Обработай балки антисептиком (защита от гнили и жучка), особенно нижние.","Уложи балки 100×200 на столбы вдоль дома, прикрути к анкерам/закладным.","Проверь уровнем горизонт и рулеткой — прямоугольник (снова диагонали!)."]',
   '{"уровень","рулетка 10 м"}',
   '["На столбах лежит гидроизоляция","Балки обработаны антисептиком","Балки 100×200 уложены и закреплены","Горизонт по уровню, диагонали равны"]',
   'Нижняя обвязка — самое уязвимое к гниению место дома. Не жалей антисептика и обязательно клади гидроизоляцию. Это те 100 рублей, что спасают дом на годы.',
   '',
   0);
end
$do$;
